  input [15:0] bus_a,
  input [15:0] bus_b,
  output equal_flag
);
  assign equal_flag = (bus_a == bus_b);
endmodule

module wrapper(
  input [15:0] val_a, val_b,
  output is_equal
);
  comp_unit c0 (
    .bus_a(val_a),
    .bus_b(val_b)
  );
endmodule

after_code:
module comp_unit(
  input [15:0] bus_a,
  input [15:0] bus_b,
